28	// ---- theme (light/dark) — applied ASAP to avoid a flash, persisted locally ----
29	function applyTheme(t) {
30	  const dark = t === "dark";
31	  document.documentElement.setAttribute("data-theme", dark ? "dark" : "light");
32	  try { localStorage.setItem("theme", dark ? "dark" : "light"); } catch (e) { /* ignore */ }
33	  const btn = document.getElementById("theme-toggle");
34	  if (btn) btn.textContent = dark ? "☀ Light" : "🌙 Dark";
35	}
36	applyTheme((() => { try { return localStorage.getItem("theme"); } catch (e) { return null; } })() || "light");
37	document.addEventListener("DOMContentLoaded", () => {
38	  const btn = document.getElementById("theme-toggle");
39	  if (btn) {
40	    applyTheme(document.documentElement.getAttribute("data-theme"));  // sync label
41	    btn.addEventListener("click", () =>
42	      applyTheme(document.documentElement.getAttribute("data-theme") === "dark" ? "light" : "dark"));
43	  }
44	});
