46	let _inflight = 0;
47	function _progress(delta) {
48	  _inflight = Math.max(0, _inflight + delta);
49	  const p = document.getElementById("progress");
50	  if (p) p.classList.toggle("active", _inflight > 0);
51	}
52	async function api(path, options) {
53	  _progress(1);
54	  try {
55	    const res = await fetch("/api" + path, {
56	      headers: { "Content-Type": "application/json" },
57	      ...options,
58	    });
59	    const body = res.status === 204 ? null : await res.json();
60	    if (!res.ok) {
61	      const detail = body && body.detail ? body.detail : res.statusText;
62	      throw new Error(typeof detail === "string" ? detail : JSON.stringify(detail));
63	    }
64	    return body;
65	  } finally {
66	    _progress(-1);
67	  }
68	}
69	function toast(text, ok = true) {
70	  const box = document.getElementById("toasts");
71	  if (!box || !text) return;
72	  const t = document.createElement("div");
73	  t.className = "toast " + (ok ? "ok" : "bad");
74	  t.setAttribute("role", ok ? "status" : "alert");
75	  t.textContent = text;
76	  box.appendChild(t);
77	  setTimeout(() => { t.style.transition = "opacity .3s"; t.style.opacity = "0"; setTimeout(() => t.remove(), 300); }, ok ? 2500 : 5000);
78	}
79	function setMsg(id, text, ok) {
80	  const el = document.getElementById(id);
81	  if (el) {
82	    el.textContent = text;
83	    el.className = "msg " + (ok ? "ok" : "bad");
84	    el.setAttribute("role", ok ? "status" : "alert");
85	    // Keep error messages visible until the next form interaction; ok messages auto-clear.
86	    if (text && ok !== false) setTimeout(() => { if (el.textContent === text) el.textContent = ""; }, 4000);
87	  }
88	  toast(text, ok);
89	}
