91	// Find the form input most likely responsible for a server error message and
92	// flag it (aria-invalid + .field-error + focus). Errors that don't match any
93	// field name fall back to the form-level message only.
94	function markInvalid(form, errorText) {
95	  if (!form || !errorText) return;
96	  // Strip prior invalid marks before re-evaluating.
97	  for (const el of form.querySelectorAll("[aria-invalid='true']")) {
98	    el.removeAttribute("aria-invalid"); el.classList.remove("field-error");
99	  }
100	  const t = String(errorText).toLowerCase();
101	  // candidates: input/select/textarea with a name
102	  const fields = [...form.elements].filter((e) => e.name);
103	  // word-boundary search: the field name (or its dash/space variants) appears in the error
104	  const hit = fields.find((e) => {
105	    const n = e.name.toLowerCase();
106	    const words = [n, n.replace(/_/g, " "), n.replace(/_/g, "-")];
107	    return words.some((w) => new RegExp("\\b" + w.replace(/[.*+?^${}()|[\]\\]/g, "\\$&") + "\\b").test(t));
108	  });
109	  if (hit) {
110	    hit.setAttribute("aria-invalid", "true"); hit.classList.add("field-error");
111	    try { hit.focus(); } catch (_) {}
112	  }
113	}
114	// Clear the invalid mark as soon as the user starts editing the flagged field.
115	document.addEventListener("input", (e) => {
116	  const t = e.target;
117	  if (t && t.getAttribute && t.getAttribute("aria-invalid") === "true") {
118	    t.removeAttribute("aria-invalid"); t.classList.remove("field-error");
119	  }
120	}, true);
