122	// Styled confirm dialog (replaces native confirm); returns a Promise<bool>.
123	function confirmDialog(message, okLabel = "Delete") {
124	  return new Promise((resolve) => {
125	    const m = document.getElementById("confirm-modal");
126	    const ok = document.getElementById("confirm-ok");
127	    const cancel = document.getElementById("confirm-cancel");
128	    document.getElementById("confirm-text").textContent = message;
129	    ok.textContent = okLabel;
130	    m.hidden = false;
131	    ok.focus();
132	    const done = (v) => {
133	      m.hidden = true;
134	      ok.removeEventListener("click", onOk);
135	      cancel.removeEventListener("click", onCancel);
136	      document.removeEventListener("keydown", onKey);
137	      resolve(v);
138	    };
139	    const onOk = () => done(true);
140	    const onCancel = () => done(false);
141	    const onKey = (e) => { if (e.key === "Escape") done(false); else if (e.key === "Enter") done(true); };
142	    ok.addEventListener("click", onOk);
143	    cancel.addEventListener("click", onCancel);
144	    document.addEventListener("keydown", onKey);
145	  });
146	}
