148	// Keyboard shortcuts: `/` focuses the active panel's filter, `n`/`N` triggers
149	// its + New / + Add button, `?` opens the shortcuts help. Skipped while the
150	// user is typing in a field. Esc-to-close-modal is handled by the detail-pane
151	// MutationObserver block elsewhere.
152	function showShortcuts() {
153	  let m = document.getElementById("shortcuts-modal");
154	  if (!m) {
155	    m = document.createElement("div"); m.id = "shortcuts-modal"; m.className = "modal";
156	    m.innerHTML = `
157	      <div class="modal-box" role="dialog" aria-modal="true" aria-labelledby="shortcuts-title">
158	        <h3 id="shortcuts-title" style="margin-top:0">Keyboard shortcuts</h3>
159	        <table class="shortcuts"><tbody>
160	          <tr><th><kbd>/</kbd></th><td>Focus the page filter</td></tr>
161	          <tr><th><kbd>n</kbd></th><td>Add a new record on the active panel</td></tr>
162	          <tr><th><kbd>Esc</kbd></th><td>Close the open dialog</td></tr>
163	          <tr><th><kbd>?</kbd></th><td>Show this help</td></tr>
164	        </tbody></table>
165	        <div class="actions-row" style="margin-top:0.75rem"><button type="button" id="shortcuts-close">Close</button></div>
166	      </div>`;
167	    document.body.appendChild(m);
168	    const close = () => { m.hidden = true; };
169	    m.querySelector("#shortcuts-close").addEventListener("click", close);
170	    m.addEventListener("click", (e) => { if (e.target === m) close(); });
171	  }
172	  m.hidden = false;
173	  requestAnimationFrame(() => m.querySelector("#shortcuts-close").focus());
174	}
175	const _shortcutsBtn = document.getElementById("shortcuts-btn");
176	if (_shortcutsBtn) _shortcutsBtn.addEventListener("click", showShortcuts);
177	document.addEventListener("keydown", (e) => {
178	  if (e.defaultPrevented) return;
179	  const a = document.activeElement;
180	  const inField = a && /^(INPUT|TEXTAREA|SELECT)$/.test(a.tagName) && a.type !== "button";
181	  if (inField) return;
182	  // Skip while a confirm dialog or shortcuts modal is open.
183	  const sm = document.getElementById("shortcuts-modal");
184	  if (sm && !sm.hidden) {
185	    if (e.key === "Escape") { sm.hidden = true; e.preventDefault(); }
186	    return;
187	  }
188	  if (e.ctrlKey || e.metaKey || e.altKey) return;
189	  if (e.key === "/") {
190	    const p = document.querySelector(".panel.active");
191	    const f = p && p.querySelector("input.filter, input[type=search]");
192	    if (f) { e.preventDefault(); f.focus(); f.select(); }
193	  } else if (e.key === "n" || e.key === "N") {
194	    const p = document.querySelector(".panel.active");
195	    const t = p && (p.querySelector(".new-btn:not(.add-trigger)") || p.querySelector(".add-trigger"));
196	    if (t) { e.preventDefault(); t.click(); }
197	  } else if (e.key === "?") {
198	    e.preventDefault(); showShortcuts();
199	  }
200	});

200	});
