202	// =================== Division + Event lookup lists ===================
203	// Loaded from the Setup catalog (/api/divisions, /api/events) on init and
204	// refreshed when those CRUDs change. The TD can add/edit/remove rows from the
205	// Setup tabs without a code change — see migration 0027 for the seed data.
206	let divisionsAll = [];
207	let eventsAll = [];
208	
209	function _populateDatalist(id, items) {
210	  const dl = document.getElementById(id);
211	  if (!dl) return;
212	  dl.innerHTML = items.map((it) => {
213	    const value = typeof it === "string" ? it : it.code;
214	    const label = typeof it === "string" ? "" : (it.label === it.code ? "" : it.label);
215	    return `<option value="${esc(value)}"${label ? ` label="${esc(label)}"` : ""}>${esc(label || value)}</option>`;
216	  }).join("");
217	}
218	// Filter divisions / events by tournament type + (optional) player gender.
219	// The catalog rows carry `tournament_type` and `gender` (null = any), so the
220	// rule reduces to: row matches its tournament_type AND (row.gender is null OR
221	// row.gender equals the player's gender OR no gender supplied).
222	function _divisionsFor(type, gender) {
223	  return divisionsAll.filter((d) => d.tournament_type === type
224	    && (d.gender == null || !gender || d.gender === gender));
225	}
226	function _eventsFor(type, gender) {
227	  return eventsAll
228	    .filter((e) => e.tournament_type === type
229	      && (e.gender == null || !gender || e.gender === gender))
230	    .map((e) => e.name);
231	}
232	function refreshDivisionLists(gender) {
233	  // Default to junior when no tournament is active so the form still has
234	  // useful suggestions on first open.
235	  const type = (active && active.type) || "junior";
236	  _populateDatalist("divisions-list", _divisionsFor(type, gender || null));
237	  _populateDatalist("events-list", _eventsFor(type, gender || null));
238	}
239	// When a division/events input gains focus, infer the player gender from the
240	// containing form (player_ref combobox, roster's player_id picker, or the
241	// inline-create gender select) and refresh the shared datalists accordingly.
242	function _inferFormGender(form) {
243	  if (!form || typeof playersById !== "object") return null;
244	  const pref = form.querySelector("[name='player_ref']");
245	  if (pref && pref.value) return (playersById[pref.value] || {}).gender || null;
246	  const picker = form.querySelector("[name='player_id']");
247	  if (picker && picker.value && !picker.disabled) {
248	    return (playersById[picker.value] || {}).gender || null;
249	  }
250	  const newRow = form.querySelector(".roster-new-row [name='gender']");
251	  if (newRow && !newRow.disabled && newRow.value) return newRow.value;
252	  return null;
253	}
254	document.addEventListener("focusin", (e) => {
255	  const t = e.target;
256	  if (!t || t.tagName !== "INPUT") return;
257	  const list = t.getAttribute("list");
258	  if (list !== "divisions-list" && list !== "events-list") return;
259	  refreshDivisionLists(_inferFormGender(t.closest("form")));
260	});
