262	// Colored status chip for known tokens (selection status, email status, etc.).
263	const BADGE = {
264	  selected: "ok", alternate: "warn", withdrawn: "bad",
265	  new: "warn", filed: "ok", needs_followup: "warn",
266	  pending: "warn", paired: "ok",
267	  mutual: "info", random: "muted",
268	  same_club: "info", siblings: "info",
269	};
270	function chip(v) {
271	  if (v == null || v === "") return "";
272	  return `<span class="badge badge-${BADGE[v] || "muted"}">${esc(v)}</span>`;
273	}
274	
275	// Open the modal overlay wrapping a workspace add-form (used when filing/editing).
276	function openForm(form) {
277	  if (form && typeof form._openModal === "function") {
278	    // file-from-email sets source_email_id before openForm() — remember the
279	    // filing flow so the modal can route back to the Inbox after close/submit.
280	    form._wasFiling = !!(form.source_email_id && form.source_email_id.value);
281	    form._openModal();
282	    return;
283	  }
284	  if (typeof syncCombos === "function") requestAnimationFrame(syncCombos);
285	}
286	function esc(v) {
287	  if (v === null || v === undefined) return "";
288	  return String(v).replace(/[&<>]/g, (c) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;" }[c]));
289	}
290	function formObj(form) {
291	  const o = {};
292	  for (const el of form.elements) if (el.name) o[el.name] = el.value === "" ? null : el.value;
293	  return o;
294	}
295	// Register a submit handler that preventDefaults and disables the submit button
296	// while the async handler runs (guards against double-submit), re-enabling after.
297	function onSubmit(form, handler) {
298	  form.addEventListener("submit", async (e) => {
299	    e.preventDefault();
300	    const btn = form.querySelector('button[type="submit"]');
301	    if (btn) btn.disabled = true;
302	    try { await handler(e); } finally { if (btn) btn.disabled = false; }
303	  });
304	}
305	function fillSelect(el, items, labelFn, none = true) {
306	  if (!el) return;
307	  const cur = el.value;
308	  el.innerHTML = none ? '<option value="">— none —</option>' : "";
309	  for (const it of items) {
310	    const o = document.createElement("option");
311	    o.value = it.id; o.textContent = labelFn(it);
312	    el.appendChild(o);
313	  }
314	  el.value = cur;
315	}
316	
317	// =================== Type-in dropdowns (searchable comboboxes) ===================
318	// Progressively enhance every native <select> into a filterable, type-to-search
319	// dropdown. The native <select> stays in the DOM as the form's source of truth
320	// (value/required/submit/listeners all unchanged) — we just overlay a text input.
321	function enhanceSelect(sel) {
322	  if (!sel || sel.dataset.combo) return;
323	  sel.dataset.combo = "1";
324	  sel.tabIndex = -1;
325	  sel.classList.add("combo-native");
326	  const wrap = document.createElement("span");
327	  wrap.className = "combo";
328	  sel.parentNode.insertBefore(wrap, sel);
329	  wrap.appendChild(sel);
330	  const listId = "combo-list-" + (enhanceSelect._n = (enhanceSelect._n || 0) + 1);
331	  const input = document.createElement("input");
332	  input.type = "text"; input.className = "combo-input"; input.autocomplete = "off";
333	  input.setAttribute("role", "combobox");
334	  input.setAttribute("aria-autocomplete", "list");
335	  input.setAttribute("aria-expanded", "false");
336	  input.setAttribute("aria-haspopup", "listbox");
337	  input.setAttribute("aria-controls", listId);
338	  // Label the overlay input from the wrapping <label>'s leading text (the native
339	  // select is tabindex=-1, so AT reads the input).
340	  const lbl = sel.closest("label");
341	  const lblText = lbl && [...lbl.childNodes].find((n) => n.nodeType === 3 && n.textContent.trim());
342	  input.setAttribute("aria-label",
343	    (sel.getAttribute("aria-label") || (lblText ? lblText.textContent : sel.name) || "select").trim());
344	  const list = document.createElement("div");
345	  list.className = "combo-list"; list.hidden = true; list.id = listId;
346	  list.setAttribute("role", "listbox");
347	  wrap.append(input, list);
348	  let shown = [], hi = -1;
349	
350	  function syncDisplay() {
351	    const o = sel.selectedOptions[0];
352	    const blank = [...sel.options].find((x) => x.value === "");
353	    // A blank/placeholder option becomes the input's grey placeholder (not its
354	    // value), so the field starts empty and you can type a search immediately.
355	    input.placeholder = blank ? blank.textContent : "";
356	    input.value = (o && o.value !== "") ? o.textContent : "";
357	    input.disabled = sel.disabled;
358	  }
359	  function render(q) {
360	    const t = (q || "").trim().toLowerCase();
361	    // The blank/placeholder option (value "") is shown as the input placeholder,
362	    // not as a selectable row. Optional fields are cleared by emptying the text.
363	    shown = [...sel.options].filter((o) => o.value !== "" && (!t || o.textContent.toLowerCase().includes(t)));
364	    list.innerHTML = "";
365	    if (!shown.length) { list.innerHTML = '<div class="combo-empty">No matches</div>'; return; }
366	    shown.forEach((o, i) => {
367	      const it = document.createElement("div");
368	      it.className = "combo-item" + (o.value === sel.value ? " sel" : "") + (i === hi ? " hi" : "");
369	      it.id = listId + "-opt-" + i;
370	      it.setAttribute("role", "option");
371	      it.setAttribute("aria-selected", o.value === sel.value ? "true" : "false");
372	      it.textContent = o.textContent;
373	      it.addEventListener("mousedown", (e) => { e.preventDefault(); choose(o); });
374	      list.appendChild(it);
375	    });
376	  }
377	  function paintHi() {
378	    [...list.children].forEach((c, i) => c.classList.toggle("hi", i === hi));
379	    const cur = list.children[hi];
380	    if (cur) { cur.scrollIntoView({ block: "nearest" }); input.setAttribute("aria-activedescendant", cur.id); }
381	    else input.removeAttribute("aria-activedescendant");
382	  }
383	  function open() { if (sel.disabled) return; render(""); hi = shown.findIndex((o) => o.value === sel.value); paintHi(); list.hidden = false; input.setAttribute("aria-expanded", "true"); }
384	  // commit=true: if the text was cleared, clear the selection (for optional fields
385	  // that have a blank "" option). Otherwise just restore the displayed value.
386	  function close(commit) {
387	    list.hidden = true; hi = -1;
388	    input.setAttribute("aria-expanded", "false");
389	    input.removeAttribute("aria-activedescendant");
390	    if (commit && input.value.trim() === "" && sel.value !== "" && [...sel.options].some((o) => o.value === "")) {
391	      sel.value = ""; sel.dispatchEvent(new Event("change", { bubbles: true }));
392	    }
393	    syncDisplay();
394	  }
395	  function choose(o) { sel.value = o.value; sel.dispatchEvent(new Event("change", { bubbles: true })); syncDisplay(); close(false); }
396	
397	  // Select existing text on focus so the first keystroke overtypes a prior choice.
398	  input.addEventListener("focus", () => { open(); input.select(); });
399	  input.addEventListener("click", open);
400	  input.addEventListener("input", () => { hi = -1; render(input.value); list.hidden = false; input.setAttribute("aria-expanded", "true"); input.removeAttribute("aria-activedescendant"); });
401	  input.addEventListener("keydown", (e) => {
402	    if (e.key === "ArrowDown") { e.preventDefault(); if (list.hidden) return open(); hi = Math.min(shown.length - 1, hi + 1); paintHi(); }
403	    else if (e.key === "ArrowUp") { e.preventDefault(); hi = Math.max(0, hi - 1); paintHi(); }
404	    else if (e.key === "Enter") { if (!list.hidden && shown[hi]) { e.preventDefault(); choose(shown[hi]); } else { e.preventDefault(); close(true); } }
405	    else if (e.key === "Escape") { if (!list.hidden) { e.preventDefault(); close(false); } }
406	  });
407	  document.addEventListener("click", (e) => { if (!wrap.contains(e.target)) close(true); });
408	
409	  // Keep the visible text in sync when options/value/disabled change in code.
410	  new MutationObserver(() => requestAnimationFrame(syncDisplay))
411	    .observe(sel, { childList: true, attributes: true, attributeFilter: ["disabled"] });
412	  sel.addEventListener("change", syncDisplay);
413	  sel._comboSync = syncDisplay;
414	  syncDisplay();
415	}
416	function enhanceAllSelects() { document.querySelectorAll("select").forEach(enhanceSelect); }
417	function syncCombos() { document.querySelectorAll("select[data-combo]").forEach((s) => s._comboSync && s._comboSync()); }
418	// form.reset() doesn't fire change — resync combos after any reset.
419	document.addEventListener("reset", () => requestAnimationFrame(syncCombos), true);
420	
421	// ---- caches + labels ----
422	const sitesById = {}, tournamentsById = {}, officialsById = {}, playersById = {}, hotelsById = {};
423	const officialLabel = (o) => `${o.last_name}, ${o.first_name}`;
424	const siteLabel = (s) => (s.code ? s.code + " — " : "") + s.name;
425	const playerLabel = (p) => `${[p.last_name, p.first_name].filter(Boolean).join(", ") || "?"} (${p.usta_number})`;
426	
427	// Certifications (value -> label) and a date formatter that appends the weekday.
428	const CERTS = [
429	  ["roving_official", "Roving official"],
430	  ["chair_umpire", "Chair umpire"],
431	  ["tournament_referee", "Tournament referee"],
432	  ["deputy_referee", "Deputy referee"],
433	  ["referee_in_training", "Referee in training"],
434	];
435	const CERT_LABEL = Object.fromEntries(CERTS);
436	const certLabel = (v) => CERT_LABEL[v] || v;
437	function fmtDOW(iso) {
438	  if (!iso) return "";
439	  const d = new Date(iso + "T00:00:00");
440	  return iso + " (" + d.toLocaleDateString("en-US", { weekday: "short" }) + ")";
441	}
442	
443	function refreshAllSelects() {
444	  fillSelect(document.getElementById("dist-official"), Object.values(officialsById), officialLabel, false);
445	  fillSelect(document.getElementById("dist-site"), Object.values(sitesById), siteLabel, false);
446	  fillSelect(document.getElementById("roster-player"), Object.values(playersById), playerLabel, false);
447	  fillSelect(document.getElementById("asg-official"), Object.values(officialsById), officialLabel, false);
448	  // asg-site is filled per-tournament in loadAssignments() (mileage site must be
449	  // one of THIS tournament's sites), so it is intentionally not filled here.
450	  fillSelect(document.getElementById("trb-hotel"), Object.values(hotelsById), (h) => h.name, false);
451	  fillPlayerRefs();
452	  // Suggest known hotel names on the player-hotel input (free text still allowed).
453	  const dl = document.getElementById("known-hotels");
454	  if (dl) dl.innerHTML = Object.values(hotelsById)
455	    .map((h) => `<option value="${esc(h.name)}"></option>`).join("");
456	}
457	
458	// Part B forms reference the existing Players list instead of free-typing a
