2082	const _SHIRT_CODES = ["YS", "YM", "YL", "AS", "AM", "AL", "AXL"];
2083	const _SHIRT_LABEL = {
2084	  YS: "Youth Small", YM: "Youth Medium", YL: "Youth Large",
2085	  AS: "Adult Small", AM: "Adult Medium", AL: "Adult Large", AXL: "Adult Extra Large",
2086	};
2087	const _SIZE_TOKEN = { s: "S", sm: "S", small: "S", m: "M", med: "M", medium: "M",
2088	  l: "L", lg: "L", large: "L", xl: "XL", xlarge: "XL", extralarge: "XL", xxl: "XL", xxxl: "XL" };
2089	// Map any stored size (full name OR legacy code like "YM") to a canonical code,
2090	// so mixed historical data aggregates into one line; unknowns return as-is.
2091	function shirtCode(v) {
2092	  if (!v) return null;
2093	  const s = String(v).toLowerCase().replace(/[^a-z]/g, "");
2094	  let group, rest;
2095	  if (/^(youth|yth|junior|jr)/.test(s) || (s[0] === "y" && s.length <= 4)) {
2096	    group = "Y"; rest = s.replace(/^(youth|yth|junior|jr|y)/, "");
2097	  } else if (/^adult/.test(s) || (s[0] === "a" && s.length <= 4)) {
2098	    group = "A"; rest = s.replace(/^(adult|a)/, "");
2099	  } else { group = "A"; rest = s; }

2100	  const sz = _SIZE_TOKEN[rest];
2101	  const code = sz && group + sz;
2102	  return _SHIRT_CODES.includes(code) ? code : String(v).trim();
2103	}
2104	function _shirtRank(code) { const i = _SHIRT_CODES.indexOf(code); return i < 0 ? 999 : i; }
