2106	function renderTshirtSummary() {
2107	  // Order quantities = the latest size per player (rows arrive newest-first per
2108	  // player), counted by canonical size. Backend excludes withdrawals/alternates.
2109	  const latest = {};
2110	  for (const r of tshirtRows) if (!(r.player_id in latest)) latest[r.player_id] = r.t_shirt_size;
2111	  const counts = {};
2112	  for (const sz of Object.values(latest)) { const c = shirtCode(sz); counts[c] = (counts[c] || 0) + 1; }
2113	  const keys = Object.keys(counts).sort((a, b) => _shirtRank(a) - _shirtRank(b) || a.localeCompare(b));
2114	  const players = Object.keys(latest).length;
2115	  const label = (c) => _SHIRT_LABEL[c] || c;
2116	  tshirtOrderRows = [["Size", "Quantity"], ...keys.map((c) => [label(c), counts[c]]), ["Total", players]];
2117	  const el = document.getElementById("tshirt-summary");
2118	  el.innerHTML = keys.length
2119	    ? `<span class="muted">Order quantities — latest size per player (${players} player${players === 1 ? "" : "s"}):</span> `
2120	      + keys.map((c) => `<span class="badge badge-info">${esc(label(c))}: ${counts[c]}</span>`).join(" ")
