2701	function _csvDownload(matrix, filename) {
2702	  const csv = matrix
2703	    .map((r) => r.map((c) => `"${String(c ?? "").replace(/"/g, '""')}"`).join(","))
2704	    .join("\r\n");
2705	  const url = URL.createObjectURL(new Blob([csv], { type: "text/csv" }));
2706	  const a = document.createElement("a");
2707	  a.href = url; a.download = filename + ".csv"; a.click();
2708	  URL.revokeObjectURL(url);
2709	}
2710	// Visible column headers (skipping the trailing actions/blank column).
2711	function _visibleHeaders(table) {
2712	  const ths = [...table.querySelectorAll("thead th")];
2713	  const keep = ths.map((th) => th.textContent.trim() !== "");
2714	  return { keep, headers: ths.filter((_, i) => keep[i]).map((th) => th.textContent.trim()) };
2715	}
2716	function exportTable(table, name) {
2717	  const { keep, headers } = _visibleHeaders(table);
2718	  const rows = [...table.querySelectorAll("tbody tr")]
2719	    .filter((tr) => !tr.querySelector(".empty"))
2720	    .map((tr) => [...tr.children].filter((_, i) => keep[i]).map((td) => td.textContent.replace(/\s+/g, " ").trim()));
2721	  _csvDownload([headers, ...rows], name);
