2784	// Promote every detail-pane to a proper ARIA dialog (role + aria-modal +
2785	// aria-labelledby) and watch the `detail-open` class to focus the first input
2786	// on open and restore focus on close. One pass at load — no per-site changes.
2787	(function _enhanceDetailDialogs() {
2788	  const obs = new MutationObserver((muts) => {
2789	    for (const m of muts) {
2790	      if (m.attributeName !== "class") continue;
2791	      const dlg = m.target;
2792	      const opening = dlg.classList.contains("detail-open");
2793	      const wasOpen = m.oldValue && m.oldValue.split(/\s+/).includes("detail-open");
2794	      if (opening && !wasOpen) {
2795	        dlg._prevFocus = document.activeElement;
2796	        requestAnimationFrame(() => {
2797	          // Prefer the first form field over the close button (querySelector
2798	          // picks by DOM order, so a multi-query gets us field-first).
2799	          const f = dlg.querySelector('input:not([type="hidden"]):not([disabled]), select:not([disabled]), textarea:not([disabled])')
2800	            || dlg.querySelector('button:not([disabled])');
2801	          if (f) try { f.focus(); } catch (_) {}
2802	        });
2803	      } else if (!opening && wasOpen && dlg._prevFocus && typeof dlg._prevFocus.focus === "function") {
2804	        try { dlg._prevFocus.focus(); } catch (_) {}
2805	      }
2806	    }
2807	  });
2808	  for (const dlg of document.querySelectorAll(".detail-pane")) {
2809	    if (!dlg.hasAttribute("role")) {
2810	      dlg.setAttribute("role", "dialog");
2811	      dlg.setAttribute("aria-modal", "true");
2812	      const title = dlg.querySelector(".detail-title");
2813	      if (title) {
2814	        if (!title.id) title.id = "dlg-" + Math.random().toString(36).slice(2, 8);
2815	        dlg.setAttribute("aria-labelledby", title.id);
2816	      }
2817	    }
2818	    obs.observe(dlg, { attributes: true, attributeOldValue: true, attributeFilter: ["class"] });
2819	  }
2820	})();
