647	#report-meta { margin-bottom: 0.6rem; }
648	
649	/* ---- responsive ---- */
650	@media (max-width: 720px) {
651	  /* Both nav rows scroll horizontally instead of wrapping into many rows. */
652	  .menu-l1, .menu { overflow-x: auto; flex-wrap: nowrap; -webkit-overflow-scrolling: touch; }
653	  .menu-group.group-active { flex-wrap: nowrap; }
654	  .gbtn, .tab { white-space: nowrap; }
655	  #context-bar { flex-wrap: wrap; }
656	  #active-tournament, #context-bar .combo, #context-bar .combo-input { min-width: 140px; }
657	}
658	
659	/* ---- print: show only the active report ---- */
660	@media print {
661	  /* Always print on white, even when the dark theme is active (saves ink / legible). */
662	  :root, :root[data-theme="dark"] {
663	    --bg: #fff; --card: #fff; --elev: #fff; --field-bg: #fff; --zebra: #fff;
664	    --ink: #000; --muted: #333; --border: #bbb;
665	  }
666	  body { background: #fff; color: #000; }
667	  header, .menu-l1, .menu, #context-bar, .no-print { display: none !important; }
668	  .panel:not(.active) { display: none !important; }
669	  .tpanel .needs-active-note { display: none !important; }
670	  main { padding: 0; max-width: none; }
671	  .card { border: 0; box-shadow: none; padding: 0; }
672	  /* don't clip scrollable tables when printing the report */
673	  .list-scroll, .tbl-scroll { max-height: none !important; overflow: visible !important; border: 0; }
674	}
